import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _not_found = {title: "Unknown", jsx: <><h2 id="haunt-not_found-error">Error</h2>
<p>Unable to find the requested haunt.</p>
</>};
const _isolation_haunt = {title: "Isolation Haunt", jsx: <><p><strong>Sources</strong> <Link to="/source/construct_handbook">Construct Handbook pg. 49</Link><br/>See the <Link to="/template/haunted_construct">Haunted Construct</Link> monster template.</p>
<p className="statblockHeaderFull"><span>Isolation Haunt</span><span>CR -</span></p>
<p><strong>XP</strong> 0<br/>NE haunt (30-ft. radius)<br/><strong>Caster Level</strong> 5th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-isolation_haunt--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to notice ambient sound disappear and other sounds grow quiet)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>-</td></tr><tr><th id="haunt-isolation_haunt--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-isolation_haunt--haunt-trigger">proximity</td><th id="haunt-isolation_haunt--haunt-reset">Reset</th><td headers="haunt-isolation_haunt--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Each targets believes it is alone in the world; it cannot perceive, target, nor interact with anyone it considers an ally. This is a mind-affecting effect. A creature that succeeds at a DC 12 Will save negates this effect.</p>
<p className="statblockSubHeader">Destruction</p>
<p>A boisterous celebration of friendship lasting at least 1 hour at the site of the haunt.</p>
</>};
const _bloody_handprints = {title: "Bloody Handprints", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 174</Link><br/>A murder or other violent death lingers as bloody marks that harm any creature touching the surface on which they appear.</p>
<p className="statblockHeaderFull"><span>Bloody Handprints</span><span>CR 1/4</span></p>
<p><strong>XP</strong> 100<br/>NE haunt (surface with area up to 5-ft. square)<br/><strong>Caster Level</strong> 1st</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-bloody_handprints--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 5 (to see dried bloody prints on the surface)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>1</td></tr><tr><th id="haunt-bloody_handprints--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-bloody_handprints--haunt-trigger">touch</td><th id="haunt-bloody_handprints--haunt-reset">Reset</th><td headers="haunt-bloody_handprints--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Bloody handprints slowly appear on the surface. Anyone touching the surface takes 1d6 points of damage.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The bloody handprints vanish if the surface is thoroughly cleaned and scrubbed with <Link to="/eq-weapon/holy_water">holy water</Link>.</p>
</>};
const _scratching_behind_the_wall = {title: "Scratching Behind the Wall", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 175</Link><br/>A lord with a terrible secret caught a servant snooping through his papers. He knocked the servant over the head and threw her into a disused dumbwaiter, which he jammed between floors. The servant awoke the following day, and her desperate attempts to escape infuse the walls that contained her.</p>
<p className="statblockHeaderFull"><span>Scratching Behind the Wall</span><span>CR 1/2</span></p>
<p><strong>XP</strong> 200<br/>CE haunt (5-ft.-by-10-ft. hallway)<br/><strong>Caster Level</strong> 1st</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-scratching_behind_the_wall--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 15 (to hear the faint scream behind the wall)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>1</td></tr><tr><th id="haunt-scratching_behind_the_wall--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-scratching_behind_the_wall--haunt-trigger">proximity</td><th id="haunt-scratching_behind_the_wall--haunt-reset">Reset</th><td headers="haunt-scratching_behind_the_wall--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The sound of claws scraping on the inside of the wall echoes throughout the hallway. Creatures within its area must succeed at a DC 11 Will save or be <Link to="/misc/shaken">shaken</Link> for 1d4 rounds.</p>
<p className="statblockSubHeader">Destruction</p>
<p>A character who finds the servant's body and removes her from behind the wall destroys the haunt forever.</p>
</>};
const _cold_spot = {title: "Cold Spot", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 175</Link><br/>Cold spots are echoes of spirits too weak to manifest as ghosts. They can occur alone or cluster around significant areas.</p>
<p className="statblockHeaderFull"><span>Cold Spot</span><span>CR 1</span></p>
<p><strong>XP</strong> 400<br/>NE haunt (5-ft. radius)<br/><strong>Caster Level</strong> 1st</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-cold_spot--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to feel the temperature dropping)</td></tr><tr><th id="haunt-cold_spot--haunt-hp">hp</th><td>2</td><th id="haunt-cold_spot--haunt-weak">Weaknesses</th><td colSpan={2}>fire (these effects can damage the haunt)</td></tr><tr><th id="haunt-cold_spot--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-cold_spot--haunt-trigger">proximity</td><th id="haunt-cold_spot--haunt-reset">Reset</th><td headers="haunt-cold_spot--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The temperature suddenly plummets below freezing. All creatures within the radius are affected as if they had been outside in <Link to="/rule/cold">cold weather</Link> for 1 hour, taking 1d6 points of nonlethal damage unless they succeed at a DC 15 Fortitude save. The cold temperature lingers for 10 minutes, but has no additional mechanical effect.</p>
<p className="statblockSubHeader">Destruction</p>
<p>If the cold spot is destroyed with holy fire (such as with <Link to="/spell/flame_strike">flame strike</Link>), it never returns.</p>
</>};
const _rapping_spirit = {title: "Rapping Spirit", jsx: <><p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 230</Link><br/>The most common haunts are rapping spirits: unquiet dead with just enough substance to produce disembodied knocking and bumps in the night. Characters can attempt communication with these intelligent spirits by working out codes the spirits can use to convey cryptic messages, or by using tools like <Link to="/magic-wondrous/spirit_planchette">spirit planchettes</Link> to increase the efficiency of communication with the spirit.</p>
<p><strong>Sources</strong> <Link to="/source/occult_mysteries">Occult Mysteries pg. 54</Link><br/>While most haunts are malevolent in nature, some are more benign and serve as a means to communicate with spirits. The most common of these haunts are rapping spirits: unquiet dead with just enough substance to produce cacophonous knocking and loud bumps in the night. Adventurers can attempt communication with these intelligent spirits by working out codes to form cryptic messages at the rate of 1d10 words per minute with a successful <Link to="/skill/linguistics">Linguistics</Link> check.</p>
<p className="statblockHeaderFull"><span>Rapping Spirit</span><span>CR 1</span></p>
<p><strong>XP</strong> 400<br/>Alignment varies persistent haunt (5-ft. radius)<br/><strong>Caster Level</strong> 1st</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-rapping_spirit--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 10 (to hear faint knocking on the walls, floor, and furniture)</td></tr><tr><th id="haunt-rapping_spirit--haunt-hp">hp</th><td>4</td><th id="haunt-rapping_spirit--haunt-weak">Weaknesses</th><td colSpan={2}>tricked by <Link to="/spell/hide_from_undead">hide from undead</Link></td></tr><tr><th id="haunt-rapping_spirit--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-rapping_spirit--haunt-trigger">proximity</td><th id="haunt-rapping_spirit--haunt-reset">Reset</th><td headers="haunt-rapping_spirit--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A chorus of agitated raps and blows rings out from nearby hard surfaces (limited to those capable of being physically manipulated by <Link to="/spell/mage_hand">mage hand</Link>) as unquiet spirits convey their unrest to the living. All who hear the supernatural knocks are affected by a <Link to="/spell/cause_fear">cause fear</Link> effect (Will DC 11 negates).</p>
<p className="statblockSubHeader">Destruction</p>
<p>Depending on its alignment, a rapping spirit typically asks for its mortal remains to be laid to rest or for the PCs to seek revenge for its death. Fulfilling the request dismisses the haunt.</p>
</>};
const _spectral_screams = {title: "Spectral Screams", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 175</Link><br/>Some spirits take joy in terrifying the living. Spectral screams are collections of lesser spirits who have banded together to increase the amount of terror they can spread.</p>
<p className="statblockHeaderFull"><span>Spectral Screams</span><span>CR 2</span></p>
<p><strong>XP</strong> 600<br/>NE haunt (10-ft. radius)<br/><strong>Caster Level</strong> 3rd</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-spectral_screams--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 10 (to hear the moaning spirits approaching)</td></tr><tr><th id="haunt-spectral_screams--haunt-hp">hp</th><td>4</td><th id="haunt-spectral_screams--haunt-weak">Weaknesses</th><td colSpan={2}><Link to="/skill/intimidate">Intimidate</Link></td></tr><tr><th id="haunt-spectral_screams--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-spectral_screams--haunt-trigger">proximity</td><th id="haunt-spectral_screams--haunt-reset">Reset</th><td headers="haunt-spectral_screams--haunt-reset">1 hour</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Spectral forms of disembodied heads emerge from the floor and scream at everyone in the area, their jaws distending to an impossible width. Creatures are affected by <Link to="/spell/scare">scare</Link>. The spectral heads take pride in terrorizing their victims; if a creature succeeds at a DC 16 Intimidate check to demonstrate its own frightening nature, the spirits decide the PC is the true winner of the current contest, after which they lose interest in the PCs for 1 hour as if reduced to 0 hit points.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The spectral screams haunt is destroyed if a creature spends 8 consecutive hours sleeping in its area.</p>
</>};
const _demanding_dead = {title: "Demanding Dead", jsx: <><p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 230</Link><br/>Some haunts influence the thoughts and actions of those in the mortal realms to communicate their anger, desires, or goals, which can lead to instances of direct-voice channeling and automatic writing. While the demanding dead are sometimes malevolent, more often there is a method to their requests, which could potentially reveal shocking secrets or the key to putting them to rest forever.</p>
<p><strong>Sources</strong> <Link to="/source/occult_mysteries">Occult Mysteries pg. 54</Link><br/>Instances of so-called direct-voice channeling, automatic writing, and talking board communications are often the result of haunts known as the possessive dead: haunts capable of influencing the thoughts and actions of those in the mortal realms to communicate their anger, desires, or goals as they seek eternal rest.</p>
<p className="statblockHeaderFull"><span>Demanding Dead</span><span>CR 3</span></p>
<p><strong>XP</strong> 800<br/>Alignment varies persistent haunt (15-ft. radius)<br/><strong>Caster Level</strong> 1st</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-demanding_dead--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 15 (to hear faint mutterings and feel a cool breeze)</td></tr><tr><th id="haunt-demanding_dead--haunt-hp">hp</th><td>13</td><th id="haunt-demanding_dead--haunt-weak">Weaknesses</th><td colSpan={2}>tricked by <Link to="/spell/hide_from_undead">hide from undead</Link></td></tr><tr><th id="haunt-demanding_dead--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-demanding_dead--haunt-trigger">proximity</td><th id="haunt-demanding_dead--haunt-reset">Reset</th><td headers="haunt-demanding_dead--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>This haunt seeks to influence the actions of the living, targeting a victim with a <Link to="/spell/suggestion">suggestion</Link> effect or a <Link to="/feat/heightened">heightened</Link> <Link to="/spell/command">command</Link> (save DC 14 for either). Depending on the haunt's alignment and goals, the suggested actions may be malicious (such as subtly putting its victims in harm's way or sowing antagonistic interactions) or benign (such as prompting mysterious automatic writings or unconscious utterances in hopes of communicating its ambitions to the world of the living).</p>
<p className="statblockSubHeader">Destruction</p>
<p>A demanding dead typically asks for rest for its mortal remains or the resolution of desires unfulfilled in life. Fulfilling the request dismisses the haunt.</p>
</>};
const _foreboding_mist = {title: "Foreboding Mist", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 175</Link><br/>Foreboding mists lurk in ill-kept graveyards, drawing their substance from the unrest of all who are buried below. They manifest regardless of the weather, and target the minds of those who fail to recognize they are not entirely real.</p>
<p className="statblockHeaderFull"><span>Foreboding Mist</span><span>CR 3</span></p>
<p><strong>XP</strong> 800<br/>NE persistent haunt (15-ft. radius)<br/><strong>Caster Level</strong> 3rd</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-foreboding_mist--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 15 (to notice a chill fog forming)</td></tr><tr><th id="haunt-foreboding_mist--haunt-hp">hp</th><td>13</td><th id="haunt-foreboding_mist--haunt-weak">Weaknesses</th><td colSpan={2}><Link to="/spell/slow">slow</Link></td></tr><tr><th id="haunt-foreboding_mist--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-foreboding_mist--haunt-trigger">proximity</td><th id="haunt-foreboding_mist--haunt-reset">Reset</th><td headers="haunt-foreboding_mist--haunt-reset">1 hour</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A chilly fog descends, twisting and condensing into claws that grab and prod those within it. This fog functions as per <Link to="/spell/haunting_mists">haunting mists</Link> (DC 13).</p>
<p className="statblockSubHeader">Destruction</p>
<p>Casting <Link to="/spell/consecrate">consecrate</Link> on the ground underneath the mist prevents it from returning.</p>
</>};
const _buried_alive = {title: "Buried Alive", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 175</Link><br/>The spirits of those unfortunate souls who are buried alive sometimes clamber to force others to share their fate.</p>
<p className="statblockHeaderFull"><span>Buried Alive</span><span>CR 4</span></p>
<p><strong>XP</strong> 1,200<br/>NE persistent haunt (15-ft. radius)<br/><strong>Caster Level</strong> 5th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-buried_alive--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear a shovel cleaving through dirt)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>18</td></tr><tr><th id="haunt-buried_alive--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-buried_alive--haunt-trigger">proximity</td><th id="haunt-buried_alive--haunt-reset">Reset</th><td headers="haunt-buried_alive--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>On the first round, spectral gravediggers create a single 15-foot-deep pit covering the haunt's entire radius. Creatures in the area must succeed at a DC 15 Reflex saving throw or fall to the bottom of the pit, taking 2d6 points of damage. Creatures who succeed leap to a square at the edge of the pit. The walls of the pit are uneven (Climb DC 20). On the second round, the spectral gravediggers fill the pit with loose, spectral dirt, burying everyone still inside. Buried creatures are <Link to="/rule/pinned">pinned</Link>, but they can reduce their condition to <em>grappled</em> with a successful DC 15 Strength check. They take 1d6 points of nonlethal damage each minute, and begin to <Link to="/rule/suffocate">suffocate</Link> after 10 minutes. Creatures outside of the pit can dig out the buried creatures. Each 5-foot cube of spectral dirt weighs 1,000 pounds; a creature can move 5 times her maximum load worth of dirt per minute, or 10 times her maximum load if she has a <Link to="/eq-misc/shovel">shovel</Link>. If the haunt is dispersed, buried creatures automatically rise to the surface.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The haunt can be permanently destroyed if a character finds the bones of the person who was buried alive, exhumes them, coats them in <Link to="/eq-weapon/holy_water">holy water</Link>, and reburies them in a temple of their patron deity.</p>
</>};
const _flytrap = {title: "Flytrap", jsx: <><p><strong>Sources</strong> <Link to="/source/pathfinder_144_midwives_to_death">Pathfinder #144: Midwives to Death pg. 65</Link>  </p>
<p className="statblockHeaderFull"><span>Flytrap</span><span>CR 4</span></p>
<p><strong>XP</strong> 1,200<br/>N persistent botanical haunt (up to 20-foot radius)<br/><strong>Caster Level</strong> 4th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-flytrap--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to spot flytrap heads opening and closing erratically)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>36</td></tr><tr><th id="haunt-flytrap--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-flytrap--haunt-trigger">proximity</td><th id="haunt-flytrap--haunt-reset">Reset</th><td headers="haunt-flytrap--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>This patch of sentient flytraps sprouts sharp hairs around its mouths and uses a highly concentrated acid to digest its prey. Each round, the flytrap haunt makes melee attacks with a +4 bonus against each creature in the affected area, dealing 2d6 points of acid damage and 1d6 points of piercing damage on a successful hit.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The nest of <Link to="/monster/accuser_devil">accuser devils</Link> making their home nearby must be eradicated.</p>
</>};
const _following_footsteps = {title: "Following Footsteps", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 133</Link>  </p>
<p className="statblockHeaderFull"><span>Following Footsteps</span><span>CR 4</span></p>
<p><strong>XP</strong> 1,200<br/>CN variant haunt (20-ft. radius)<br/><strong>Aura</strong> moderate enchantment (compulsion)<br/><strong>Caster Level</strong> 7th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-following_footsteps--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 10 (to notice nearby strange footprints and hear rustling in nearby underbrush)</td></tr><tr><th id="haunt-following_footsteps--haunt-hp">hp</th><td>8</td><th id="haunt-following_footsteps--haunt-weak">Weaknesses</th><td colSpan={2}>negative energy (see <Link to="/rule/echoes_of_the_first_world">echoes of the first world</Link>)</td></tr><tr><th id="haunt-following_footsteps--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-following_footsteps--haunt-trigger">proximity</td><th id="haunt-following_footsteps--haunt-reset">Reset</th><td headers="haunt-following_footsteps--haunt-reset">1 week</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Strange animal noises pervade the underbrush within the area of the echo, and strange tracks can be easily discovered. Non-fey viewing the tracks are <Link to="/misc/fascinated">fascinated</Link> by them and are compelled to follow (DC 16 Will negates). Each creature that fails this save follows a different set of tracks only it can perceive, moving in a random direction for up to 1 minute at a speed of 20 feet per round. This effect continues even if the creature leaves the echo's area. At the end of each of its turns following the tracks, a creature can attempt a new Will saving throw to negate the effect. If it fails three such saving throws, the creature must follow the tracks for the remaining duration. <Link to="/spell/break_enchantment">Break enchantment</Link> or a similar effect cast on an affected creature removes this compulsion. This is a mind-affecting effect.</p>
<p className="statblockSubHeader">Destruction</p>
<p>A character who succeeds at her initial saving throw against the compulsion can attempt to deal damage against the echo by disrupting the original tracks. This requires the use of <Link to="/skill/survival">Survival</Link> as a full-round action. With a successful DC 24 Survival check, such a character deals 1d6 points of damage to the echo. If the result of the Survival check used in this way is a natural 20, she deals 2d6 points of damage to the echo instead. Casting <Link to="/spell/find_the_path">find the path</Link> and touching the tracks (treating it as a creature for this use) destroys the haunt instantly.</p>
</>};
const _belated_arrival = {title: "Belated Arrival", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 176</Link><br/>The regret of those who arrived too late to spare others a terrible fate can manifest as a haunt. A belated arrival haunt often arises near another haunt or undead, representing the fate that these regretful spirits were not fast enough to stop. A belated arrival haunt is often chained to a <Link to="/template/ghost">ghost</Link> but a <Link to="/monster/necrocraft">necrocraft</Link> is a truly horrifying alternative.</p>
<p className="statblockHeaderFull"><span>Belated Arrival</span><span>CR 5</span></p>
<p><strong>XP</strong> 1,600<br/>N chained haunt (25-ft. radius)<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-belated_arrival--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear running footsteps)</td></tr><tr><th id="haunt-belated_arrival--haunt-hp">hp</th><td>22</td><th id="haunt-belated_arrival--haunt-weak">Weaknesses</th><td colSpan={2}><Link to="/spell/slow">slow</Link></td></tr><tr><th id="haunt-belated_arrival--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-belated_arrival--haunt-trigger">proximity</td><th id="haunt-belated_arrival--haunt-reset">Reset</th><td headers="haunt-belated_arrival--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The spectral forms of several people take faltering steps before falling to their knees and wailing with grief. All creatures in the area are <Link to="/misc/exhausted">exhausted</Link> (no save, as per <Link to="/spell/waves_of_exhaustion">waves of exhaustion</Link>) and are slowed for 13 minutes as per <em>slow</em> unless they succeed at a DC 16 Will saving throw.</p>
<p className="statblockSubHeader">Destruction</p>
<p>These spirits find rest only if those they could not save lead them to the afterlife.</p>
</>};
const _bleeding_walls = {title: "Bleeding Walls", jsx: <><p><strong>Sources</strong> <Link to="/source/gamemastery_guide">GameMastery Guide pg. 243</Link>  </p>
<p className="statblockHeaderFull"><span>Bleeding Walls</span><span>CR 5</span></p>
<p><strong>XP</strong> 1,600<br/>CE haunt (5ft. by 20 ft. hallway)<br/><strong>Caster Level</strong> 5th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-bleeding_walls--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear the sound of soft sobbing)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>10</td></tr><tr><th id="haunt-bleeding_walls--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-bleeding_walls--haunt-trigger">proximity</td><th id="haunt-bleeding_walls--haunt-reset">Reset</th><td headers="haunt-bleeding_walls--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>When this haunt is triggered, thick rivulets of blood course down the walls accompanied by the shrill shriek of a woman's scream. All creatures in the hallway are targeted by a <Link to="/spell/fear">fear</Link> spell (save DC 16).</p>
<p className="statblockSubHeader">Destruction</p>
<p>The body of the maid entombed behind the walls must be extracted and given a proper burial.</p>
</>};
const _spectral_vermin = {title: "Spectral Vermin", jsx: <><p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 231</Link><br/>Overwhelming, unresolved guilt - or horrific death by thousands of tiny teeth - can lead to the manifestation of ghostly vermin swarms. The haunted area often displays signs of ancient rodent infestation.</p>
<p className="statblockHeaderFull"><span>Spectral Vermin</span><span>CR 5</span></p>
<p><strong>XP</strong> 1,600<br/>CE free-roaming persistent vaporous haunt (30-ft.-by-30-ft. room)<br/><strong>Caster Level</strong> 5th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-spectral_vermin--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 15 (to hear scratching in walls)</td></tr><tr><th id="haunt-spectral_vermin--haunt-hp">hp</th><td>22</td><th id="haunt-spectral_vermin--haunt-weak">Weaknesses</th><td colSpan={2}>tricked by <Link to="/spell/hide_from_undead">hide from undead</Link></td></tr><tr><th id="haunt-spectral_vermin--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-spectral_vermin--haunt-trigger">proximity</td><th id="haunt-spectral_vermin--haunt-reset">Reset</th><td headers="haunt-spectral_vermin--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>This free-roaming haunt wanders the vacant halls of old manors and dank dungeons. When the haunt is triggered, the skeletal remains of spectral rats burst forth from every crack and crevice of the room, scurrying over the area and voraciously consuming trespassers, as the <Link to="/spell/summon_swarm">summon swarm</Link> spell.</p>
<p className="statblockSubHeader">Destruction</p>
<p>A character must ritually kill a common cat in the area. The cat's ghost manifests and consumes the ectoplasmic swarm over the course of 1 week, earning both the cat and the rats permanent rest.</p>
</>};
const _arcane_storm = {title: "Arcane Storm", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 174</Link><br/>Each spell, no matter how weak, leaves its signature on the world for a short time, which spellcasters can perceive as a lingering magical aura. When dozens of powerful spells are hurled against each other over a small area, reality itself can form scars that affect all who come near them.</p>
<p>Magical scars have auras and count as ongoing spell effects for the purposes of <Link to="/spell/detect_magic">detect magic</Link> and similar spells. A successful Spellcraft check to identify a scar reveals its effect and its weakness, and, if it succeeds by 10 or more, the scar's benefit. A creature can't attempt to activate a benefit it hasn't identified. Spells that automatically reveal the nature of magical effects, such as <Link to="/spell/greater_arcane_sight">greater arcane sight</Link>, automatically reveal all of these properties. The destruction conditions for magical scars are more obscure, and require research or exploration to uncover.</p>
<p>The arcane storm haunt arose when a pair of evokers dueled to the death centuries ago. An echo of the duel still rages at the site of their battle, and the charred ground tells the bitter tale.</p>
<p className="statblockHeaderFull"><span>Arcane Storm</span><span>CR 6</span></p>
<p><strong>XP</strong> 2,400<br/>N persistent variant haunt (30-ft. radius)<br/><strong>Aura</strong> faint evocation<br/><strong>Caster Level</strong> 5th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-arcane_storm--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception or Spellcraft DC 20 (to hear the sound of clashing energy or deduce the effect from the charred ground)</td></tr><tr><th id="haunt-arcane_storm--haunt-hp">hp</th><td>27</td><th id="haunt-arcane_storm--haunt-weak">Weaknesses</th><td colSpan={2}>energy damage (immune to positive energy)</td></tr><tr><th id="haunt-arcane_storm--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-arcane_storm--haunt-trigger">proximity</td><th id="haunt-arcane_storm--haunt-reset">Reset</th><td headers="haunt-arcane_storm--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Each round, the arcane storm fires a bolt of energy to hit as many creatures as possible in its area (Reflex DC 15 halves). This functions as per <Link to="/spell/lightning_bolt">lightning bolt</Link>, except the energy type cycles between acid, cold, electricity, and fire. The storm is immune to the most recent type of energy damage it has dealt.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The arcane storm is destroyed if a character successfully <Link to="/rule/counterspells">counterspells</Link> four of its bolts in a row.</p>
</>};
const _death_of_curchanus = {title: "Death of Curchanus", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 62</Link><br/>Long ago, the god Curchanus was the patron of beasts and travel. The demon lord Lamashtu envied Curchanus's power and seized an opportunity to lead Curchanus into a trap. With the god in her clutches, Lamashtu wrenched away his dominion over beasts and claimed it for herself by murdering Curchanus. Although Lamashtu was unable to stop Curchanus from granting his dominion over travel to his friend Desna, she siphoned enough power from the god to fuel her own ascent into divinity over his withered husk.</p>
<p className="statblockHeaderFull"><span>Death of Curchanus</span><span>CR 6</span></p>
<p><strong>XP</strong> 2,400<br/>CE persistent variant haunt (20-ft. radius)<br/><strong>Caster Level</strong> 6th; <strong>Deity</strong> <Link to="/faith/lamashtu">Lamashtu</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-death_of_curchanus--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 0 (to hear the sound of howling and screeching beasts)</td></tr><tr><th id="haunt-death_of_curchanus--haunt-hp">hp</th><td>27</td><th id="haunt-death_of_curchanus--haunt-weak">Weaknesses</th><td colSpan={2}>good or lawful spells or effects</td></tr><tr><th id="haunt-death_of_curchanus--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-death_of_curchanus--haunt-trigger">proximity</td><th id="haunt-death_of_curchanus--haunt-reset">Reset</th><td headers="haunt-death_of_curchanus--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Remnants of Lamashtu's power awaken bestial ferocity within those who walk upon this unholy ground. All creatures must succeed at a DC 16 Will saving throw or experience the effects of the <Link to="/spell/moonstruck">moonstruck</Link> spell. Additionally, worshipers of <Link to="/faith/desna">Desna</Link> who fail the saving throw take 2d6 points of slashing, bludgeoning, and piercing damage each round for the next 5 rounds as deep gashes and bite marks appear all over their bodies. These bites do not count as an attacker for the purposes of determining a Desnan's actions. Creatures that worship Lamashtu gain the bite and claw attacks that <em>moonstruck</em> grants for 24 hours without any ill effects. If they already have claws or a bite attack, these attacks deal damage as if they were <Link to="/misc/two_size_categories_larger">two size categories larger</Link>.</p>
<p className="statblockSubHeader">Destruction</p>
<p>If a cleric of Desna with the <Link to="/domain/travel">Travel</Link> domain casts <Link to="/spell/find_the_path">find the path</Link> on the resonance, it is permanently destroyed. When the spell is cast in this way, it has no other effect.</p>
<hr/>
<h3 id="haunt-death_of_curchanus-miraculous-resonances">Miraculous Resonances</h3>
<p>When deities interact with the world directly, their influence can persist in the form of miraculous resonances. These regions often become pilgrimage sites for the deity's worshipers.</p>
<p>The resonances sense the presence of their creator's influence and react differently to their creator's followers than to all others they encounter. Typically, they grant the faithful a benefit for 24 hours, though a single pilgrim can receive a manifestation's blessing only once. A miraculous resonance haunt has an alignment identical to the deity with which it resonates. These resonances typically manifest in areas where the associated deity's worship has traditionally been strong, but they can appear anywhere where such worship is particularly potent or where the deity has brushed against the Material Plane at some point in the past.</p>
<p>Miraculous resonances are vulnerable to forces connected to other deities, as well as spells that oppose their deity's nature. Spells with an alignment descriptor that does not match the haunt's alignment deal 1d6 points of damage per spell level (or the spell's damage against an aligned outsider, whichever is higher). While weapon attacks cannot normally harm miraculous resonances, these haunts take any extra damage that specifically affects creatures of their alignment, such as the 2d6 points of extra damage from a <Link to="/magic-enh/holy">holy</Link> weapon or the extra damage from a paladin's smite evil. Such attacks target an AC of 5. <Link to="/ability/channel_energy">Channeled energy</Link> can damage a resonance, so long as the creature channeling the energy has a patron deity of a different alignment than the haunt.</p>
</>};
const _unsolved_murder = {title: "Unsolved Murder", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 176</Link><br/>After a merchant was murdered at a party being held to celebrate his latest venture, his spirit was obsessed with finding his killer and exacting vengeance. It has clung to his body for years, hoping for a hapless grave robber to inadvertently become the pawn of his unfinished business.</p>
<p className="statblockHeaderFull"><span>Unsolved Murder</span><span>CR 6</span></p>
<p><strong>XP</strong> 2,400<br/>NE latent persistent possessing haunt (up to a 30-ft. radius)<br/><strong>Caster Level</strong> 6th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-unsolved_murder--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 25 (to notice the corpse's hand twitching)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>27</td></tr><tr><th id="haunt-unsolved_murder--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-unsolved_murder--haunt-trigger">touch</td><th id="haunt-unsolved_murder--haunt-reset">Reset</th><td headers="haunt-unsolved_murder--haunt-reset">1 week</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The merchant's spirit subtly possesses the creature who touched his corpse (even if the creature touched it with a tool), as per <Link to="/spell/riding_possession">riding possession</Link> (Will DC 17 negates), except he and the host can communicate telepathically. He nudges his host toward investigating his murder. On any day his host makes progress, he is pleased and grants his host a +2 morale bonus on skill checks. If his host does not make progress for 1 week, he curses his host in a fit of rage. This functions as per <Link to="/spell/bestow_curse">bestow curse</Link> (Will DC 16 negates), except the spirit can remove it whenever he chooses. He can apply one new curse per week.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The merchant's spirit can rest only if the murderer dies in an act of revenge. If the murderer dies of other causes before this can happen, the merchant's spirit demands another form of harsh vengeance against the murderer's memory or family.</p>
</>};
const _betrayal = {title: "Betrayal", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 176</Link><br/>When the sting of betrayal lingers beyond the grave, it can manifest as a disjointed mass of confused and paranoid spiritual energy that can turn even the closest of allies against one another.</p>
<p className="statblockHeaderFull"><span>Betrayal</span><span>CR 7</span></p>
<p><strong>XP</strong> 3,200<br/>CE persistent haunt (30-ft. radius)<br/><strong>Caster Level</strong> 7th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-betrayal--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception or Sense Motive DC 20 (to see the outllines of a dozen cloaked figures begin to form or feel a suden sense of suspicion)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>31</td></tr><tr><th id="haunt-betrayal--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-betrayal--haunt-trigger">proximity</td><th id="haunt-betrayal--haunt-reset">Reset</th><td headers="haunt-betrayal--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>As dozens of cloaked figures swarm the area, the line between friend and foe blurs, and paranoia descends upon everyone within the haunt's area, as per <Link to="/spell/confusion">confusion</Link> (Will DC 15 negates). Furthermore, creatures within the haunt's area must attempt a DC 15 Will saving throw against the haunt's curse. Until it is removed, the curse forces its victims to attempt saving throws against spells, including those designated harmless. Additionally, the victims cannot benefit from any effect that requires them to treat another creature as an ally, such as <Link to="/rule/flanking">flanking</Link> or <Link to="/rule/aid_another_2">aid another</Link>. <Link to="/spell/remove_curse">Remove curse</Link> can remove this effect.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The betrayal haunt is destroyed if a victim falls unconscious or dies because of damage it took on behalf of another creature in the area. Any spell or ability that allows for the transfer of damage, such as <Link to="/spell/shield_other">shield other</Link> or a <Link to="/mystery/life">life</Link> oracle's lifelink ability, satisfies this haunt's requirement. This doesn't work if the characters in question colluded to manufacture the damage transfer to destroy the haunt; it works only if it was a truly selfless act of protecting another.</p>
</>};
const _droughts_end = {title: "Drought's End", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 62</Link><br/>The dualistic deity Gozreh, as ancient as the sky and the sea themselves, rarely interferes directly in mortal affairs. He is a gentle breeze and a fierce hurricane, speaking in the whisper of wind through rustling leaves and the ground-shaking rumble of thunder. When Gozreh answered the prayers of a coastal village shriveling under a drought, she unleashed a mighty thunderstorm over the entire region. A small portion of the storm still rages centuries later, granting boons to the faithful who prove themselves against its fury.</p>
<p className="statblockHeaderFull"><span>Drought's End</span><span>CR 7</span></p>
<p><strong>XP</strong> 3,200<br/>N persistent variant haunt (30-ft. radius)<br/><strong>Caster Level</strong> 7th; <strong>Deity</strong> <Link to="/faith/gozreh">Gozreh</Link></p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-droughts_end--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 0 (to hear a rumbling thunderstorm)</td></tr><tr><th id="haunt-droughts_end--haunt-hp">hp</th><td>31</td><th id="haunt-droughts_end--haunt-weak">Weaknesses</th><td colSpan={2}>chaotic, evil, good, or lawful effects</td></tr><tr><th id="haunt-droughts_end--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-droughts_end--haunt-trigger">proximity</td><th id="haunt-droughts_end--haunt-reset">Reset</th><td headers="haunt-droughts_end--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A fierce storm rages, bringing <Link to="/rule/winds">windstorm-strength winds</Link> and <Link to="/rule/weather">pouring rain</Link>. Each round for 6 rounds, a bolt of lightning strikes a random creature within the area, dealing 5d10 points of damage (Reflex DC 17 half). A worshiper of Gozreh who stays in the area of the resonance for its entire 6-round duration gains the ability to cast each of the following spells once, with a caster level equal to her Hit Dice: <Link to="/spell/alter_winds">alter winds</Link>, <Link to="/spell/resist_energy">resist energy</Link> (electricity only), and <Link to="/spell/water_breathing">water breathing</Link>. The ability to cast these spells persists until it is expended.</p>
<p className="statblockSubHeader">Destruction</p>
<p><Link to="/spell/control_weather">Control weather</Link> immediately destroys this haunt. When the spell is cast to destroy a drought's end, the spell has no other effect on the surrounding weather.</p>
<hr/>
<h3 id="haunt-droughts_end-miraculous-resonances">Miraculous Resonances</h3>
<p>When deities interact with the world directly, their influence can persist in the form of miraculous resonances. These regions often become pilgrimage sites for the deity's worshipers.</p>
<p>The resonances sense the presence of their creator's influence and react differently to their creator's followers than to all others they encounter. Typically, they grant the faithful a benefit for 24 hours, though a single pilgrim can receive a manifestation's blessing only once. A miraculous resonance haunt has an alignment identical to the deity with which it resonates. These resonances typically manifest in areas where the associated deity's worship has traditionally been strong, but they can appear anywhere where such worship is particularly potent or where the deity has brushed against the Material Plane at some point in the past.</p>
<p>Miraculous resonances are vulnerable to forces connected to other deities, as well as spells that oppose their deity's nature. Spells with an alignment descriptor that does not match the haunt's alignment deal 1d6 points of damage per spell level (or the spell's damage against an aligned outsider, whichever is higher). While weapon attacks cannot normally harm miraculous resonances, these haunts take any extra damage that specifically affects creatures of their alignment, such as the 2d6 points of extra damage from a <Link to="/magic-enh/holy">holy</Link> weapon or the extra damage from a paladin's smite evil. Such attacks target an AC of 5. <Link to="/ability/channel_energy">Channeled energy</Link> can damage a resonance, so long as the creature channeling the energy has a patron deity of a different alignment than the haunt.</p>
</>};
const _malignant_weapon = {title: "Malignant Weapon", jsx: <><p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 231</Link><br/>Sometimes a weapon that slays a powerful <Link to="/class/witch">witch</Link> or <Link to="/family/hag">hag</Link> becomes tainted by the victim's malignant hatred. Although haunted weapons often still bear holy marks from the original owners or relics like bones from a revered saint, these are never sufficient to contain the malevolence that dwells within the weapon.</p>
<p className="statblockHeaderFull"><span>Malignant Weapon</span><span>CR 7</span></p>
<p><strong>XP</strong> 3,200<br/>LE persistent item-bound haunt (haunted object affecting up to a 35-ft. radius)<br/><strong>Caster Level</strong> 7th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-malignant_weapon--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 25 (to hear distant cackling when touching the weapon)</td></tr><tr><th id="haunt-malignant_weapon--haunt-hp">hp</th><td>36</td><th id="haunt-malignant_weapon--haunt-weak">Weaknesses</th><td colSpan={2}>tricked by <Link to="/spell/invisibility">invisibility</Link></td></tr><tr><th id="haunt-malignant_weapon--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-malignant_weapon--haunt-trigger">special (see below)</td><th id="haunt-malignant_weapon--haunt-reset">Reset</th><td headers="haunt-malignant_weapon--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Whenever the wielder of the haunted weapon threatens a critical hit with the weapon, the area immediately resonates with a cacophonous cackling. All creatures within a 35-foot radius centered on the weapon suffer the effects of a <Link to="/spell/song_of_discord">song of discord</Link> spell (Will DC 17 negates) for the next 8 rounds. If the weapon's wielder is affected, she gains a +2 bonus on the critical confirmation roll.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The weapon must be boiled in the cauldron of a willing hag's coven, which destroys both the weapon and the cauldron at the same time.</p>
</>};
const _bountiful_feast = {title: "Bountiful Feast", jsx: <><p><strong>Sources</strong> <Link to="/source/pathfinder_144_midwives_to_death">Pathfinder #144: Midwives to Death pg. 65</Link>  </p>
<p className="statblockHeaderFull"><span>Bountiful Feast</span><span>CR 8</span></p>
<p><strong>XP</strong> 4,800<br/>N persistent botanical haunt (up to 40-foot radius)<br/><strong>Caster Level</strong> 8th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-bountiful_feast--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Knowledge (nature) or Survival DC 25 (to notice abnormalities in its fruits)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>72</td></tr><tr><th id="haunt-bountiful_feast--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-bountiful_feast--haunt-trigger">touch</td><th id="haunt-bountiful_feast--haunt-reset">Reset</th><td headers="haunt-bountiful_feast--haunt-reset">1 hour</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>This haunt appears as a large grove of trees or patch of berry-laden bushes covered in perfectly ripe and delicious-looking fruit native to the area. The haunt notices Small or larger creatures and triggers as soon as such a creature attempts to grab a fruit. As soon as it is triggered, the fruits near every Small or larger creature in the area explode into a cloud of carnivorous seeds coated in poison that infest their targets' flesh.</p>
<p>These seeds have two effects. First, the poison is a powerful neurotoxin that paralyzes its victims.</p>
<div className="sideNoteWrap"><ScrollContainer id="haunt-bountiful_feast--table-1"><table><tbody><tr><ThLink scope="row" rowSpan={9} to="/rule/poison"><IonIcon aria-label="Poison" icon="/icons/poison-bottle.svg" /></ThLink><th colSpan={4} scope="col" className="title">Bountiful Feast</th></tr><tr><th scope="row">Type</th><td colSpan={3}>Poison; contact</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 20</td></tr><tr><th scope="row">Onset</th><td colSpan={3}>immediate</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/round for 10 rounds</td></tr><tr><th scope="row">Effect</th><td colSpan={3}><Link to="/rule/paralysis">paralysis</Link> for 1 round</td></tr><tr><th scope="row">Cure</th><td colSpan={3}>2 consecutive saves</td></tr></tbody></table></ScrollContainer></div><p>Second, the seeds quickly feed upon unmoving prey; on each round that an infested creature does not spend a move action to move at least 10 feet, it must succeed at a DC 18 Fortitude save or take 1d6 points of <Link to="/rule/constitution_damage">Constitution damage</Link> as the seeds feed upon the nutrients in its body. This effect ends only if the haunt is destroyed or the seeds are removed from the creature's body (see below). If a creature dies from this Constitution damage, its body explodes into a 5-foot-radius area of fruiting plants that is added to the haunt's area (even if it is outside of the haunt's typical radius). For each point of Constitution damage the seeds deal, the haunt gains 3 <Link to="/rule/temporary_hit_points">temporary hit points</Link>. These temporary hit points last for 1 hour.</p>
<p>Extracting the seeds from an affected creature requires a successful DC 25 Heal check as a standard action. Regardless of whether the check succeeds or fails, the target takes an amount of damage equal to 1d6 times the amount of Constitution damage it has already taken from the seeds. Spells such as <Link to="/spell/remove_disease">remove disease</Link> and <Link to="/spell/heal">heal</Link> can also treat the affliction, in which case the target doesn't take hit point damage.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The demon-possessed <Link to="/monster/dryad">dryad</Link> in the nearby crypt must be defeated and its ashes scattered around the dryad's tree.</p>
</>};
const _dimensional_tear = {title: "Dimensional Tear", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 133</Link>  </p>
<p className="statblockHeaderFull"><span>Dimensional Tear</span><span>CR 8</span></p>
<p><strong>XP</strong> 4,800<br/>N persistent variant haunt (30-ft. radius)<br/><strong>Aura</strong> moderate conjuration (calling)<br/><strong>Caster Level</strong> 13th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-dimensional_tear--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 18 (to see rippling, rainbow-hued distortions in the air)</td></tr><tr><th id="haunt-dimensional_tear--haunt-hp">hp</th><td>27</td><th id="haunt-dimensional_tear--haunt-weak">Weaknesses</th><td colSpan={2}>negative energy (see <Link to="/rule/echoes_of_the_first_world">echoes of the first world</Link>)</td></tr><tr><th id="haunt-dimensional_tear--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-dimensional_tear--haunt-trigger">proximity</td><th id="haunt-dimensional_tear--haunt-reset">Reset</th><td headers="haunt-dimensional_tear--haunt-reset">undefined</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>As soon as a Small or larger creature enters the area of a dimensional tear, it is affected as if by <Link to="/spell/plane_shift">plane shift</Link> and must succeed at a Will save (DC 21) or be immediately transported to <Link to="/rule/the_first_world">the First World</Link>. When this occurs, a creature from the First World (determined randomly from the <Link to="/spell/summon_natures_ally_vi">summon nature's ally VI</Link> list) is teleported to a space adjacent to the echo, determined by the GM. The creature has a starting attitude of hostile.</p>
<p className="statblockSubHeader">Overcharge</p>
<p>Determine the First World creature called using the <Link to="/spell/summon_natures_ally_vii">summon nature's ally VII</Link> list instead, and then add the <Link to="/template/fey_creature">fey creature template</Link>.</p>
<p className="statblockSubHeader">Destruction</p>
<p>A character with <em>plane shift</em> prepared can attempt to <Link to="/rule/counterspells">counterspell</Link> the echo's effect. Successfully doing so destroys the dimensional tear.</p>
</>};
const _robotic_reactivation = {title: "Robotic Reactivation", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 63</Link><br/>When an ancient starship crashed on Numerian soil millennia ago, countless robots emerged, terrorizing anyone unfortunate enough to cross their paths. Some robots still lie dormant within the scattered wreckage, waiting for a signal or a stray surge of power to reactivate.</p>
<p className="statblockHeaderFull"><span>Robotic Reactivation</span><span>CR 8</span></p>
<p><strong>XP</strong> 4,800<br/>N chained persistent variant haunt (20-ft. radius centered on the activated robot)<br/><strong>Caster Level</strong> 8th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-robotic_reactivation--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear whirring mechanisms springing to life)</td></tr><tr><th id="haunt-robotic_reactivation--haunt-hp">hp</th><td>36</td><th id="haunt-robotic_reactivation--haunt-weak">Weaknesses</th><td colSpan={2}>harmed by <Link to="/skill/disable_device">Disable Device</Link> DC 23 and electricity effects (immune to positive energy)</td></tr><tr><th id="haunt-robotic_reactivation--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-robotic_reactivation--haunt-trigger">proximity</td><th id="haunt-robotic_reactivation--haunt-reset">Reset</th><td headers="haunt-robotic_reactivation--haunt-reset">1 hour</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A whirling cloud of miniature repair robots animates and reactivates a dormant <Link to="/monster/myrmidon_robot">myrmidon robot</Link>. The repair robots follow the myrmidon and augment its defenses. The myrmidon's force field improves to 75 hit points with <Link to="/umr/fast_healing">fast healing</Link> of 15, and the myrmidon gains a +2 bonus on all saving throws and to AC.</p>
<p className="statblockSubHeader">Destruction</p>
<p>Destroying the myrmidon prevents this technological surge from recurring.</p>
<hr/>
<h3 id="haunt-robotic_reactivation-technological-surges">Technological Surges</h3>
<p>Advanced technology remains a mystery to most denizens of Golarion. In places where these wonders lie abandoned, such as the wrecks of the starships that crashed on Numerian soil or the mysterious halls of the Empty Lands of Apostae, strange interactions with unstable power sources can coax circuits back to life. GMs might consider using these same rules to handle other advanced magic and technology, such as a malfunctioning Shory sky city or a newly uncovered marvel of Azlanti electro-thaumaturgy.</p>
<p>The animating force behind technological surges is not life energy, but electricity. As such, technological surges cannot be harmed with positive or negative energy. Instead, stopping them requires shutting down their function. Anyone trained in Disable Device can use the skill to attempt to disrupt the surge, and characters with the <Link to="/feat/technologist">Technologist</Link> feat can use Knowledge (engineering) instead and gain a +5 bonus on either skill check. The DC of the skill check is equal to 15 + the haunt's CR. Each successful check deals 5 points of damage plus 1 additional point of damage per point by which the result exceeds the DC. A <Link to="/spell/discharge">discharge</Link> or <Link to="/spell/greater_discharge">greater discharge</Link> spell that targets a technological surge inflicts damage equal to the spell's caster level (for <em>discharge</em>) or 1d4 points per caster level (for <em>greater discharge</em>). Electromagnetic effects, such as those caused by an EMP pistol or rifle, inflict normal damage to a technological surge. Other similar effects may well have an impact on a surge at the GM's discretion.</p>
<p>A technological surge's caster level represents its strength. Technological surges are completely nonmagical. Their effects cannot be disrupted with <Link to="/spell/antimagic_field">antimagic field</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, or similar abilities, even when they replicate spell effects. All technological surges are neutral aligned.</p>
</>};
const _watery_grave = {title: "Watery Grave", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 177</Link><br/>Watery grave haunts typically travel aboard ghost ships, protecting the ghost vessel's passengers. When the ghost ship's captain boards an enemy vessel, the watery grave haunt drifts aboard as well.</p>
<p className="statblockHeaderFull"><span>Watery Grave</span><span>CR 8</span></p>
<p><strong>XP</strong> 4,800<br/>CE chained free-roaming persistent haunt (one ship, up to a 40-ft. radius)<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-watery_grave--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear bubbles rising to the surface of the water)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>36</td></tr><tr><th id="haunt-watery_grave--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-watery_grave--haunt-trigger">proximity</td><th id="haunt-watery_grave--haunt-reset">Reset</th><td headers="haunt-watery_grave--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A ghostly tendril of water erupts from the sea and forces itself into the lungs of a living creature aboard the ship, which then begins to drown. This functions as per <Link to="/spell/suffocation">suffocation</Link> (Fortitude DC 17 negates). The haunt affects one additional victim each round until it is dispersed.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The watery grave haunt is destroyed if the <Link to="/monster/ghost_captain">ghost ship's captain</Link> is permanently destroyed.</p>
</>};
const _devouring_maws = {title: "Devouring Maws", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 177</Link><br/>A pack of ravenous <Link to="/monster/ghoul">ghouls</Link> descended upon a once-peaceful town, killing or transforming all of its denizens who were not fast enough to flee. The ghouls' unending hunger blended with the townsfolk's horrifying memories of death to produce the devouring maws haunt.</p>
<p className="statblockHeaderFull"><span>Devouring Maws</span><span>CR 9</span></p>
<p><strong>XP</strong> 6,400<br/>CE persistent haunt (30-ft. radius)<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-devouring_maws--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear teeth scraping againt bone)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>40</td></tr><tr><th id="haunt-devouring_maws--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-devouring_maws--haunt-trigger">proximity</td><th id="haunt-devouring_maws--haunt-reset">Reset</th><td headers="haunt-devouring_maws--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A swarm of disembodied mouths fills the area. Each humanoid creature in the area must succeed at a DC 21 Fortitude save or be paralyzed, as per <Link to="/spell/mass_hold_person">mass hold person</Link>. The maws swarm around paralyzed creatures, dealing them 4d6 points of damage per round. <Link to="/race/elves">Elves</Link> are immune to the effects of this haunt.</p>
<p className="statblockSubHeader">Destruction</p>
<p>Living (though not necessarily sentient) creatures with a combined weight of at least 10,000 pounds must be left in the area to be devoured over the course of a single day.</p>
</>};
const _insidious_presence = {title: "Insidious Presence", jsx: <><p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 231</Link><br/>This haunt hides within a host's body, at first offering tempting boons to make the host comfortable with their presence before ultimately seeking the host's destruction.</p>
<p className="statblockHeaderFull"><span>Insidious Presence</span><span>CR 9</span></p>
<p><strong>XP</strong> 6,400<br/>NE possessing persistent spiteful haunt (45-ft. radius when not possessing a creature)<br/><strong>Caster Level</strong> 10th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-insidious_presence--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to feel a malignant presence and hear faint mutterings)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>40</td></tr><tr><th id="haunt-insidious_presence--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-insidious_presence--haunt-trigger">proximity</td><th id="haunt-insidious_presence--haunt-reset">Reset</th><td headers="haunt-insidious_presence--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>This haunt subtly possesses a living host as <Link to="/spell/possession">possession</Link> (Will DC 20 negates) in order to sow fear and injury in the wider world. When it first possesses a host creature, the insidious presence may offer enticing boons for several months using its <Link to="/spell/shadow_conjuration">shadow conjuration</Link> effect (such as summoning allies to assist the host). But soon, the haunt's inner malignancy takes over as it uses its <em>shadow conjuration</em> (DC 18 where applicable) to produce harmful or even deadly effects against its host.</p>
<p>An insidious presence that has slain a number of different hosts equal to its CR undergoes a startling transformation. This powerful entity has CR of 12, learns to utilize <Link to="/spell/greater_shadow_conjuration">greater shadow conjuration</Link> (DC 22 where applicable), has a caster level of 14, has a radius of 60 feet when not possessing a creature, and has 54 hit points.</p>
<p className="statblockSubHeader">Destruction</p>
<p>An insidious presence can be destroyed only if an innocent creature willingly accepts it into its body and then intentionally sacrifices its life to destroy the haunt forever.</p>
</>};
const _network_of_lasers = {title: "Network of Lasers", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 63</Link><br/>The wards guarding priceless artifacts can persist long after the treasures they protect have faded into obscurity. Whatever safety measures once kept these ancient wards in check are long forgotten, and those foolhardy enough to explore the ruins of technologically advanced civilizations face the remnants of their defenses.</p>
<p className="statblockHeaderFull"><span>Network of Lasers</span><span>CR 9</span></p>
<p><strong>XP</strong> 6,400<br/>N persistent variant haunt (up to 45-ft.-square room)<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-network_of_lasers--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 30 (to hear a faint humming)</td></tr><tr><th id="haunt-network_of_lasers--haunt-hp">hp</th><td>40</td><th id="haunt-network_of_lasers--haunt-weak">Weaknesses</th><td colSpan={2}>harmed by <Link to="/skill/disable_device">Disable Device</Link> DC 24 (immune to positive energy)</td></tr><tr><th id="haunt-network_of_lasers--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-network_of_lasers--haunt-trigger">proximity</td><th id="haunt-network_of_lasers--haunt-reset">Reset</th><td headers="haunt-network_of_lasers--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>On the first round, a network of lasers detects all corporeal Diminutive or larger creatures in the area, excluding invisible creatures. Heavy blast doors drop to bar creatures from exiting the room (break DC 35). On the second round, one laser activates for each creature detected and fires concentrated beams at its targets (+12 touch, 5d6 points of fire damage). The lasers fire each round for 5 rounds unless disabled or destroyed. Destroying the lasers without disabling the surge is difficult - each laser has 10 hardness and 20 hp. The blast doors reopen if the surge is disabled or if all of the laser guns are destroyed.</p>
<p className="statblockSubHeader">Destruction</p>
<p>Disabling the surge is sufficient to stop the network from reactivating.</p>
<hr/>
<h3 id="haunt-network_of_lasers-technological-surges">Technological Surges</h3>
<p>Advanced technology remains a mystery to most denizens of Golarion. In places where these wonders lie abandoned, such as the wrecks of the starships that crashed on Numerian soil or the mysterious halls of the Empty Lands of Apostae, strange interactions with unstable power sources can coax circuits back to life. GMs might consider using these same rules to handle other advanced magic and technology, such as a malfunctioning Shory sky city or a newly uncovered marvel of Azlanti electro-thaumaturgy.</p>
<p>The animating force behind technological surges is not life energy, but electricity. As such, technological surges cannot be harmed with positive or negative energy. Instead, stopping them requires shutting down their function. Anyone trained in Disable Device can use the skill to attempt to disrupt the surge, and characters with the <Link to="/feat/technologist">Technologist</Link> feat can use Knowledge (engineering) instead and gain a +5 bonus on either skill check. The DC of the skill check is equal to 15 + the haunt's CR. Each successful check deals 5 points of damage plus 1 additional point of damage per point by which the result exceeds the DC. A <Link to="/spell/discharge">discharge</Link> or <Link to="/spell/greater_discharge">greater discharge</Link> spell that targets a technological surge inflicts damage equal to the spell's caster level (for <em>discharge</em>) or 1d4 points per caster level (for <em>greater discharge</em>). Electromagnetic effects, such as those caused by an EMP pistol or rifle, inflict normal damage to a technological surge. Other similar effects may well have an impact on a surge at the GM's discretion.</p>
<p>A technological surge's caster level represents its strength. Technological surges are completely nonmagical. Their effects cannot be disrupted with <Link to="/spell/antimagic_field">antimagic field</Link>, <Link to="/spell/dispel_magic">dispel magic</Link>, or similar abilities, even when they replicate spell effects. All technological surges are neutral aligned.</p>
</>};
const _shifting_seasons = {title: "Shifting Seasons", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 61</Link><br/>The most powerful beings in <Link to="/rule/the_first_world">the First World</Link> are the <Link to="/rule/eldest">Eldest</Link>, divine creatures who can transform large swaths of the plane to suit their interests. Mortal scholars know little about the Eldest, with <Link to="/faith/ng">Ng the Hooded</Link>, who is connected to the shifting seasons, proving particularly inscrutable. Seasonal haunts manifest at crossroads in the Material Plane connected to the paths Ng treads in the First World.</p>
<p>See <Link to="/rule/echoes_of_the_first_world">Echoes of the First World</Link> for more info on this variant haunt.</p>
<p className="statblockHeaderFull"><span>Shifting Seasons</span><span>CR 9</span></p>
<p><strong>XP</strong> 6,400<br/>CN persistent variant haunt (40-ft. radius)<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-shifting_seasons--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to smell a faint floral odor)</td></tr><tr><th id="haunt-shifting_seasons--haunt-hp">hp</th><td>40</td><th id="haunt-shifting_seasons--haunt-weak">Weaknesses</th><td colSpan={2}>negative energy (immune to positive energy)</td></tr><tr><th id="haunt-shifting_seasons--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-shifting_seasons--haunt-trigger">proximity</td><th id="haunt-shifting_seasons--haunt-reset">Reset</th><td headers="haunt-shifting_seasons--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The surrounding area begins to rapidly cycle through manifestations of the season. Each season lasts 1 round, and the haunt cycles through the seasons three times (lasting 12 rounds total). On the spring round, flowers bloom, spreading a thick cloud of pollen that blocks sight (as per <Link to="/spell/obscuring_mist">obscuring mist</Link>) and requires each creature within the area to succeed at a DC 18 Fortitude saving throw or sneeze violently, gaining the <Link to="/misc/staggered">staggered</Link> condition for 1 round. On the summer round, the pollen falls out of the air as the atmosphere becomes unbearably hot and dry, dealing 8d6 points of damage (Fortitude DC 18 half). Half of this damage is fire damage, and the other half is untyped damage from desiccation. On the autumn round, ropes of decaying leaves grasp at all creatures in the area, as per <Link to="/spell/black_tentacles">black tentacles</Link>. Finally, on the winter round, a heavy hailstorm strikes, as per <Link to="/spell/ice_storm">ice storm</Link>.</p>
<p className="statblockSubHeader">Overcharge</p>
<p>During a spring round, seeds join the pollen spray, implanting themselves in the flesh of all living creatures that fail a DC 18 Fortitude saving throw. These seeds deal 1d4 points of <Link to="/rule/strength_damage">Strength damage</Link>. A summer round becomes hotter, dealing 12d6 points of fire and untyped damage instead of 8d6. On an autumn round, the leaves become razor sharp, dealing 1d6 points of <Link to="/rule/bleed">bleed</Link> damage to any foe they grapple. A winter round produces a more bitter chill and causes any creature that fails a DC 18 Fortitude saving throw to become staggered and move at half speed for 1 minute.</p>
<p className="statblockSubHeader">Destruction</p>
<p>To destroy the haunt, a character must use a spell or effect that counters a seasonal effect with one associated with the opposite season (for example, a fire effect during the winter round, or an <Link to="/spell/entangle">entangle</Link> spell during the autumn round) for 4 consecutive rounds.</p>
</>};
const _enchanting_demise = {title: "Enchanting Demise", jsx: <><p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 133</Link>  </p>
<p className="statblockHeaderFull"><span>Enchanting Demise</span><span>CR 10</span></p>
<p><strong>XP</strong> 9,600<br/>CN persistent variant haunt (80-ft. radius)<br/><strong>Aura</strong> moderate enchantment (compulsion) [mind-affecting]<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-enchanting_demise--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception or Knowledge (nature) DC 15 (to notice drifting motes of shimmering pollen in the air)</td></tr><tr><th id="haunt-enchanting_demise--haunt-hp">hp</th><td>45</td><th id="haunt-enchanting_demise--haunt-weak">Weaknesses</th><td colSpan={2}>negative energy (see <Link to="/rule/echoes_of_the_first_world">echoes of the first world</Link>)</td></tr><tr><th id="haunt-enchanting_demise--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-enchanting_demise--haunt-trigger">proximity</td><th id="haunt-enchanting_demise--haunt-reset">Reset</th><td headers="haunt-enchanting_demise--haunt-reset">undefined</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Every minute a creature spends within an enchanting demise, that creature must succeed at a DC 25 Will save or fall asleep as though affected by <Link to="/spell/deep_slumber">deep slumber</Link>. Creatures that fail this save and fall asleep take 1 point of <Link to="/rule/wisdom_damage">Wisdom damage</Link> each minute they sleep within the area of an enchanting demise. A creature that succeeds at this Will saving throw remains awake, but it must attempt a new saving throw after 1 minute if it does not leave the enchanting demise's area. A creature reduced to 0 Wisdom by this effect dies and blooms into a field of colorful wildflowers with a radius of 5 feet per Hit Die the creature had. If this radius would extend beyond the radius of the enchanting demise, it instead expands the radius of the echo out to the border of the created wildflowers. The presence of such wildflowers reduces the Perception DC to notice the echo by 2.</p>
<p className="statblockSubHeader">Overcharge</p>
<p>Sleeping creatures take 1d4 points of Wisdom drain each minute instead of 1 per minute.</p>
<p className="statblockSubHeader">Destruction</p>
<p>A character with the <Link to="/feat/lucid_dreamer">Lucid Dreamer</Link> feat who falls asleep in an enchanting demise intrusion can attempt to destroy it permanently in the Dimension of Dreams. When such a character falls asleep, he receives one attempt to successfully form a <Link to="/rule/dimension_of_dreams">lucid body</Link> without disadvantage. If he fails this check, he does not successfully lucid dream and remains in a dreamless slumber. If the character succeeds at this check, he can immediately attempt a DC 15 Charisma check to affect the boundary between the Dimension of Dreams, the Material Plane, and <Link to="/rule/the_first_world">the First World</Link>. If he succeeds, the enchanting demise is destroyed and all sleeping creatures in its area wake up. If the character fails, he immediately ceases lucid dreaming and falls into a deep, dreamless sleep.</p>
</>};
const _living_decay = {title: "Living Decay", jsx: <><p>Among the most frightening diseases are those that cause their victims' bodies to rot away. A living decay haunt arises when an epidemic of such a disease devastates a population.</p>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 177</Link></p>
<p className="statblockHeaderFull"><span>Living Decay</span><span>CR 10</span></p>
<p><strong>XP</strong> 9,600<br/>NE persistent haunt (50-ft. radius)<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-living_decay--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to smell decaying flesh)</td></tr><tr><th id="haunt-living_decay--haunt-hp">hp</th><td>45</td><th id="haunt-living_decay--haunt-weak">Weaknesses</th><td colSpan={2}><Link to="/spell/remove_disease">remove disease</Link></td></tr><tr><th id="haunt-living_decay--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-living_decay--haunt-trigger">proximity</td><th id="haunt-living_decay--haunt-reset">Reset</th><td headers="haunt-living_decay--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The area fills with a potent miasma that reeks of decaying flesh. Everyone within the radius must succeed at a DC 20 Fortitude save or contract the disease living rot, as detailed below, except they bypass the latent/carrier state. Within the haunt's area, the disease's frequency increases to 1 round and its save DC increases to 20. Characters who succeed at this saving throw are not immune; they must attempt a new saving throw each round they remain in the haunt's area. Reducing the haunt to 0 hit points does not remove the disease. A character who casts <em>remove disease</em> on the living decay haunt deals it an amount of damage equal to her caster level.</p>
<p className="statblockSubHeader">Destruction</p>
<p>Casting <Link to="/spell/heal">heal</Link> on each remaining body in the original victims' mass grave (or a single casting of <Link to="/spell/mass_heal">mass heal</Link>) prevents this haunt from returning.</p>
<h3 id="haunt-living_decay-living-rot">Living Rot</h3>
<p>This haunt uses the <Link to="/rule/diseases_pu">optional Unchained disease rules</Link>.</p>
<div className="sideNoteWrap"><ScrollContainer id="haunt-living_decay--table-1"><table><tbody><tr><th scope="row" rowSpan={7}><IonIcon aria-label="Disease" icon="/icons/paramecia.svg" /></th><th scope="row">Type</th><td colSpan={3}>Disease, contact, inhaled, or injury</td></tr><tr><th scope="row">Save DC</th><td colSpan={3}>Fort 17</td></tr><tr><th scope="row">Frequency</th><td colSpan={3}>1/day</td></tr><tr><th scope="row">Track</th><td colSpan={3}><Link to="/rule/physical_disease_track">physical</Link></td></tr><tr><th scope="row">Effect</th><td colSpan={3}>In the weakened state, the target also takes a -2 penalty on Strength- and Dexterity-based skill checks and ability checks. In the impaired state, the target takes a 50% miss chance on attack rolls and the target's speed is reduced by half (minimum 5 feet). All objects touched at the impaired state and beyond can transfer the disease.</td></tr><tr><th scope="row">Cure</th><td colSpan={3}>2 consecutive saves, penalties from the weakened state and worse are permanent until the victim is the target of <Link to="/spell/heal">heal</Link> or <Link to="/spell/regenerate">regenerate</Link></td></tr></tbody></table></ScrollContainer></div></>};
const _whispers_from_beyond = {title: "Whispers from Beyond", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 173</Link><br/><strong>Maddening Influence</strong> haunts are tied to the reality-warping influence of beings beyond comprehension. The only way to hold these haunts at bay is to draw upon dark knowledge, but such knowledge comes at a cost. As a full-round action, any character within the haunt's area can attempt an appropriate Knowledge check to perform a short rite, utter an arcane word, or otherwise quell the maddening influence (DC = 15 + the haunt's CR). If successful, the haunt takes 5 points of damage plus additional damage equal to the amount the character exceeded the DC.</p>
<p>This haunt is an example of a maddening influence formed at the site of a mass ritual suicide. The murmurs worm their way into the minds of all who hear them and leave lasting wounds.</p>
<p className="statblockHeaderFull"><span>Whispers from Beyond</span><span>CR 10</span></p>
<p><strong>XP</strong> 9,600<br/>CE free-roaming persistent variant haunt (30-ft. radiu)<br/><strong>Caster Level</strong> 9th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-whispers_from_beyond--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 25 (to hear whispers emerging from inside the skulls of all nearby creatures)</td></tr><tr><th id="haunt-whispers_from_beyond--haunt-hp">hp</th><td>45</td><th id="haunt-whispers_from_beyond--haunt-weak">Weaknesses</th><td colSpan={2}>harmed by Knowledge (arcana, planes, or religion) DC 25 (immune to positive energy)</td></tr><tr><th id="haunt-whispers_from_beyond--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-whispers_from_beyond--haunt-trigger">proximity</td><th id="haunt-whispers_from_beyond--haunt-reset">Reset</th><td headers="haunt-whispers_from_beyond--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The whispers drift toward sentient beings, particularly those whose minds they have touched before. Each creature in the area must succeed at a DC 16 Will save or take 1d8 points of <Link to="/rule/wisdom_damage">Wisdom damage</Link>, or 1 Wisdom damage on a successful save (or if you are using the <Link to="/rule/sanity">sanity system</Link>, 1d6 points of sanity damage on a successful save or 2d8 points on a failed save). The DC increases by 1 for each round a creature spends within the haunt's area (these rounds need not be consecutive, though a given creature's DC resets to 16 after 24 hours and whenever the haunt is dispersed). Each time a creature damages this haunt, it must succeed at a Will save with a DC equal to its Knowledge check result or take 1d4 Wisdom drain (or, if you are using the sanity system, 1d8 points of sanity damage on a successful save or 2d10 points on a failed save).</p>
<p className="statblockSubHeader">Destruction</p>
<p>The haunt is destroyed if the corpses of all the cultists who created it are cremated and buried on consecrated ground.</p>
</>};
const _psychic_echo_anger = {title: "Psychic Echo (Anger)", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 174</Link><br/>Sometimes, the collective emotional energy of significant or traumatic events creates a lasting psychic impression, even in places not associated with death. These psychic haunts are mind-affecting emotion effects. A character who uses <Link to="/spell/analyze_aura">analyze aura</Link> or the <Link to="/skill/read_aura">read aura skill unlock</Link> on a psychic haunt's area automatically detects the haunt and receives cryptic clues about how to put it to rest.</p>
<p>Every psychic haunt focuses on a specific emotion, and when targeted by or within the area of effect of an emotion spell or effect that is not connected to the associated emotion, they take damage equal to three times the effect's spell level (each spell deals damage to the haunt once, regardless of its duration). <em>Calm emotions</em> damages psychic haunts regardless of their associated emotion, and an emotion effect without a spell level deals an amount of damage equal to the HD of the creature who created the effect. A character can calm a psychic haunt with a Diplomacy check (DC = 15 + the haunt's CR). If successful, the haunt takes 5 points of damage plus additional damage equal to the amount the character exceeded the DC.</p>
<p>This psychic echo haunt lies in the heart of an abandoned village. A group of raiders drove the villagers from their home by the sword, but an echo of the villagers' fury persists, stoking hatred against all members of the raiders' ethnic group.</p>
<p className="statblockHeaderFull"><span>Psychic Echo (Anger)</span><span>CR 10</span></p>
<p><strong>XP</strong> 9,600<br/>N persistent variant haunt (30-ft. radius)<br/><strong>Caster Level</strong> 11th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-psychic_echo_anger--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Sense Motive DC 25 (to sense an internal spark of anger)</td></tr><tr><th id="haunt-psychic_echo_anger--haunt-hp">hp</th><td>45</td><th id="haunt-psychic_echo_anger--haunt-weak">Weaknesses</th><td colSpan={2}>emotion effects and <Link to="/spell/calm_emotions">calm emotions</Link> (immune to positive energy)</td></tr><tr><th id="haunt-psychic_echo_anger--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-psychic_echo_anger--haunt-trigger">proximity</td><th id="haunt-psychic_echo_anger--haunt-reset">Reset</th><td headers="haunt-psychic_echo_anger--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>As per <Link to="/spell/foster_hatred">foster hatred</Link>, except any creature that fails a DC 19 Will save becomes hostile toward members of the raiders' ethnic group.</p>
<p className="statblockSubHeader">Destruction</p>
<p>To destroy the haunt, two people, one each of the villagers' and raiders' ethnicity must reveal their true love for one another (typically by marrying) within the haunt's area.</p>
</>};
const _servants_of_the_book = {title: "Servants of the Book", jsx: <><p><strong>Sources</strong> <Link to="/source/book_of_the_damned">Book of the Damned pg. 167</Link><br/>The Book of the Damned was never meant for mortal eyes. Even so, over ages of wandering, the elusive tome has granted countless reckless scholars a glimpse of reality's deepest evils. Those who aren't driven to ruin by the book's secrets typically face the knives of covetous thieves, which ensures that the blasphemous volume never lingers in one place for long. At any given time, ambitious fiends, evil cultists, and unscrupulous spellcasters are the most likely guardians of the Book of the Damned - the book's disparate pieces are not always found in the hands of mighty beings.</p>
<p>The Book of the Damned rarely spends more than a decade in any one creature's possession. This is in part because of its power, which makes it difficult to hide, and its propensity for drawing the scrutiny of extraplanar evils. Yet most who have held and lost the book refuse to let go of it. Over the ages, the blood of a thousand cultists has spilled upon the tome, giving rise to a vicious haunt that jealously tries to tear the Book of the Damned from any single owner's grip.</p>
<p className="statblockHeaderFull"><span>Servants of the Book</span><span>CR 10</span></p>
<p><strong>XP</strong> 9,600<br/>NE haunt (20-ft.-radius circle centered on the <Link to="/magic-artifact/book_of_the_damned">Book of the Damned</Link>)<br/><strong>Caster Level</strong> 10th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-servants_of_the_book--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 28 (to hear eerie changing and faint screams)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>20</td></tr><tr><th id="haunt-servants_of_the_book--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-servants_of_the_book--haunt-trigger">proximity</td><th id="haunt-servants_of_the_book--haunt-reset">Reset</th><td headers="haunt-servants_of_the_book--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>This haunt activates at the whim of the multitude of spirits and foul impressions it comprises (at the GM's discretion, but generally not until a single evil creature has owned the Book of the Damned for more than a month, or perhaps only after a few rounds after a good creature carries the book). When the servants of the book awaken, the creature with the highest Charisma within 20 feet of the Book of the Damned must attempt a DC 21 Charisma check. If the creature succeeds and is evil, there is no effect; the spirits surrounding the tome accept the newcomer's dominance. If the creature succeeds and is not evil, all creatures within 20 feet of the tome must succeed at a DC 21 Will saving throw or be affected as per the spell <Link to="/spell/nightmare">nightmare</Link>. If the creature attempting the Charisma check fails, all creatures within the area must attempt saves to resist the <em>nightmare</em> effect (as above) and the haunt uses the <Link to="/spell/telekinesis">telekinesis</Link> spell either to harm a creature or to fling the Book of the Damned out of its bearer's possession. The intensity of the spirits that constitute this haunt makes the DC to resist its effects higher than usual. The haunt cannot trigger while in the area of a <Link to="/spell/hallow">hallow</Link> effect.</p>
<p className="statblockSubHeader">Destruction</p>
<p>If the complete Book of the Damned is destroyed, the haunt ends.</p>
</>};
const _eternal_pyre = {title: "Eternal Pyre", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 178</Link><br/>An eternal pyre is formed from the spirits of people who were burned alive during an overzealous witch trial. It hates all living beings, but it has a strong bond of kinship with the <Link to="/monster/witchfire">witchfire</Link> who arose from the most powerful of those spirits. The witchfire often lurks within the haunt's area, as her witchflame intensifies the power of the pyre's strikes, which in turn heal her.</p>
<p className="statblockHeaderFull"><span>Eternal Pyre</span><span>CR 11</span></p>
<p><strong>XP</strong> 12,800<br/>CE chained fast free-roaming persistent spiteful tenacious haunt (30-ft. radius)<br/><strong>Caster Level</strong> 11th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-eternal_pyre--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear the crackling of a fire)</td></tr><tr><th id="haunt-eternal_pyre--haunt-hp">hp</th><td>49</td><th id="haunt-eternal_pyre--haunt-weak">Weaknesses</th><td colSpan={2}>water spells and effects (these effects damage the haunt)</td></tr><tr><th id="haunt-eternal_pyre--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-eternal_pyre--haunt-trigger">proximity</td><th id="haunt-eternal_pyre--haunt-reset">Reset</th><td headers="haunt-eternal_pyre--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A pillar of black and red flames manifests within the haunt's area each round. This pillar functions as per <Link to="/spell/flame_strike">flame strike</Link> (Reflex DC 19 negates), except its damage is half fire and half negative energy.</p>
<p className="statblockSubHeader">Destruction</p>
<p>Destroying the witchfire also destroys the eternal pyre haunt.</p>
</>};
const _spawn_of_the_abyss = {title: "Spawn of the Abyss", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 172</Link><br/>Dimensional instabilities are areas where the boundary between the Material Plane and another plane is thin and rifts between the planes frequently open. They take damage from effects that oppose the connected plane's fundamental nature. For example, a dimensional instability associated with the chaotic evil Abyss takes damage from good or lawful spells or effects, and an instability tied to the Elemental Plane of Fire takes damage from water and cold effects. Instabilities can even provide benefits to those who know how to cultivate them.</p>
<p>This particular haunt appeared when an ancient wizard bound 666 demons. Over time, the boundary between the Abyss and his summoning chamber grew thin, and the plane's influence fractured the binding circle he carved into the floor, creating tiny rifts that flicker into existence at irregular intervals.</p>
<p>In addition to good and lawful effects, the haunt is vulnerable to other damage associated with good or law at the GM's discretion, such as the extra damage from a <Link to="/magic-enh/holy">holy</Link> weapon.</p>
<p className="statblockHeaderFull"><span>Spawn of the Abyss</span><span>CR 11</span></p>
<p><strong>XP</strong> 12,800<br/>CN persistent vaporous variant haunt (40-ft. radius)<br/><strong>Aura</strong> Aura strong conjuration<br/><strong>Caster Level</strong> 13th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-spawn_of_the_abyss--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception or Knowledge (arcana) DC 25 (to notice a faint shimmering or recognize the significance of the fractured circle)</td></tr><tr><th id="haunt-spawn_of_the_abyss--haunt-hp">hp</th><td>49</td><th id="haunt-spawn_of_the_abyss--haunt-weak">Weaknesses</th><td colSpan={2}>good and lawful effects (immune to positive energy)</td></tr><tr><th id="haunt-spawn_of_the_abyss--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-spawn_of_the_abyss--haunt-trigger">proximity</td><th id="haunt-spawn_of_the_abyss--haunt-reset">Reset</th><td headers="haunt-spawn_of_the_abyss--haunt-reset">1d20 days</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>When a mortal creature enters the area, it's presence provokes curiosity from the other side. The instability begins spewing a demon each round, and continues doing so for 1 minute. Use the following chart to determine what demon appears. These demons are not summoned.</p>
<ScrollContainer id="haunt-spawn_of_the_abyss--table-1"><table>
<thead>
<tr>
<th>d4</th>
<th>Demon</th>
</tr>
</thead>
<tbody><tr>
<td>1</td>
<td><Link to="/monster/dretch">Dretch</Link> (CR 2)</td>
</tr>
<tr>
<td>2</td>
<td><Link to="/monster/babau">Babau</Link> (CR 6)</td>
</tr>
<tr>
<td>3</td>
<td><Link to="/monster/succubus">Succubus</Link> (CR 7)</td>
</tr>
<tr>
<td>4</td>
<td><Link to="/monster/nabasu">Nabasu</Link> (CR 8)</td>
</tr>
</tbody></table></ScrollContainer>
<p className="statblockSubHeader">Benefit</p>
<p>A character can channel the instability's power by spending 1 minute in the area while performing a ritual to focus its energy, requiring a DC 30 Knowledge (arcana) or Knowledge (planes) check. If she succeeds, she gains the <Link to="/template/fiendish">fiendish</Link> template for 24 hours, and her alignment shifts one step closer to chaotic evil. If she fails, she is pulled into <Link to="/rule/the_abyss">the Abyss</Link>.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The instability can only be permanently closed with a <Link to="/spell/miracle">miracle</Link> or <Link to="/spell/wish">wish</Link> spell. A <Link to="/spell/hallow">hallow</Link> spell tied to a <Link to="/spell/dimensional_anchor">dimensional anchor</Link> can temporarily prevent the instability's effects.</p>
</>};
const _breach_to_the_quickening = {title: "Breach to the Quickening", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_realms">Horror Realms pg. 60</Link><br/>The Quickening is the most chaotic portion of the First World, a region so unstable that most of the denizens of <Link to="/rule/the_first_world">the First World</Link> give it a wide berth. Even a brief journey into the Quickening is enough to transform body and mind in unforeseeable ways. Connections between the Quickening and the Material Plane are rare and fleeting, but their effects persist.</p>
<p>See <Link to="/rule/echoes_of_the_first_world">Echoes of the First World</Link> for more info on this variant haunt.</p>
<p className="statblockHeaderFull"><span>Breach to the Quickening</span><span>CR 12</span></p>
<p><strong>XP</strong> 19,200<br/>CN persistent variant haunt (30-ft. radius)<br/><strong>Caster Level</strong> 12th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-breach_to_the_quickening--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to notice nearby plant and animal life beginning to twist and deform)</td></tr><tr><th id="haunt-breach_to_the_quickening--haunt-hp">hp</th><td>54</td><th id="haunt-breach_to_the_quickening--haunt-weak">Weaknesses</th><td colSpan={2}>negative energy (immune to positive energy)</td></tr><tr><th id="haunt-breach_to_the_quickening--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-breach_to_the_quickening--haunt-trigger">proximity</td><th id="haunt-breach_to_the_quickening--haunt-reset">Reset</th><td headers="haunt-breach_to_the_quickening--haunt-reset">1d20 days</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Colorful light and raw chaotic energy lash out in a dizzying display. All living creatures become the target of a random quickening effect (see table below; DC 21 Fortitude saving throw negates). A creature that remains in the breach's area of effect must attempt an additional saving throw each round against a new random effect.</p>
<p className="statblockSubHeader">Overcharge</p>
<p>Each affected target rolls twice on the quickening effect table if they fail to resist this haunt's effects.</p>
<ScrollContainer id="haunt-breach_to_the_quickening--table-1"><table>
<thead>
<tr>
<th>d%</th>
<th>Quickening Effect</th>
</tr>
</thead>
<tbody><tr>
<td>01-25</td>
<td>The target transforms into a Tiny animal that is not native to the local region (as per <Link to="/spell/baleful_polymorph">baleful polymorph</Link>). As typical for that spell, a creature that fails the initial Fortitude saving throw must succeed at a secondary Will saving throw or lose significant mental abilities.</td>
</tr>
<tr>
<td>26-40</td>
<td>The target gains a random mutation from the <Link to="/template/mutant">mutant</Link> creature template, with the exception of radiation affinity.<sup><InnerLink showBacklink="backlink-haunt-breach_to_the_quickening-ref-M-1" id="haunt-breach_to_the_quickening-ref-M-1" data-hash-target to="haunt-breach_to_the_quickening-M">1</InnerLink></sup> Roll 1d20 to select the mutation.</td>
</tr>
<tr>
<td>41-75</td>
<td>The target gains a random deformity from the mutant creature template. Roll 1d12 to select the specific deformity.</td>
</tr>
<tr>
<td>76-95</td>
<td>The First World lashes out at the target vindictively, bestowing the <Link to="/corruption/accursed">accursed</Link> corruption.</td>
</tr>
<tr>
<td>96-99</td>
<td>The target gains a new form. This effect functions as per <Link to="/spell/reincarnate">reincarnate</Link>, with a few exceptions. It takes full effect when the breach triggers, rather than taking 1 hour to activate. Additionally, it works only on living creatures, it does not impose any negative levels, and it does not cause a spellcaster to lose spells. Restoring the target to its original form requires a <Link to="/spell/miracle">miracle</Link> or <Link to="/spell/wish">wish</Link> spell.</td>
</tr>
<tr>
<td>100</td>
<td>The target gains the <Link to="/template/fey_creature">fey creature template</Link>, and its alignment changes to chaotic neutral. Restoring the target's original form requires a <em>miracle</em> or <em>wish</em> spell.</td>
</tr>
</tbody></table></ScrollContainer>
<p className="statblockSubHeader">Destruction</p>
<p>Breaches to the Quickening spontaneously close or move on their own as unpredictably as they appear. A <Link to="/spell/forbiddance">forbiddance</Link> or <Link to="/spell/dimensional_lock">dimensional lock</Link> cast on the area of a breach prevents the breach from exerting influence on the Material Plane until it moves to a different location. A <em>wish</em> or <em>miracle</em> spell permanently closes a breach.</p>
<section data-footnotes>
<h3 id="haunt-breach_to_the_quickening-label">Footnotes</h3>
<ol>
<li id="haunt-breach_to_the_quickening-M">
<p>No mutation mentioning "radiation affinity" exists in that template. <InnerLink id="backlink-haunt-breach_to_the_quickening-ref-M-1" data-hash-target to="haunt-breach_to_the_quickening-ref-M-1" aria-label="Back to reference M-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _dissolving_vat = {title: "Dissolving Vat", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 178</Link><br/>A sadistic alchemist conducted experiments on test subjects within his remote laboratory. When he was finished with his subjects, he threw them into a vat of harsh chemicals to dissolve. His victims' spirits have permeated the vat, and they reach out with their oozing spectral forms toward any who come near.</p>
<p className="statblockHeaderFull"><span>Dissolving Vat</span><span>CR 12</span></p>
<p><strong>XP</strong> 19,200<br/>CE fast persistent haunt (60-ft. radius centered around the vat)<br/><strong>Caster Level</strong> 11th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-dissolving_vat--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to smell the acrid chemical tang growing stronger)</td></tr><tr><th id="haunt-dissolving_vat--haunt-hp">hp</th><td>54</td><th id="haunt-dissolving_vat--haunt-weak">Weaknesses</th><td colSpan={2}>vulnerable to acid damage (these effects damage the haunt)</td></tr><tr><th id="haunt-dissolving_vat--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-dissolving_vat--haunt-trigger">proximity</td><th id="haunt-dissolving_vat--haunt-reset">Reset</th><td headers="haunt-dissolving_vat--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The chemical vat boils and froths, and spits its contents at everyone within its range each round as a ranged touch attack (+15 to hit, 4d6+6 points of damage). This damage ignores damage reduction and energy resistance. A creature hit by the chemicals must succeed at a DC 18 Fortitude save or become liquefied, as its bones and muscles melt into a pile of oozing flesh. The DC of this saving throw increases by 1 for each chemical ball that has hit the creature in the past 24 hours. A liquefied creature cannot carry, use, or wear any items, and its Dexterity score is reduced to 1. It loses all physical attacks, and it cannot cast spells with verbal or somatic components. It gains a slam attack appropriate for a creature of one size category larger than its size (for example, 1d6 points of damage if Medium). Additionally, it gains immunity to critical hits, flanking, paralysis, poison, polymorph, sleep, and stun. A liquefied creature reverts to its normal state if the haunt is reduced to 0 hit points; otherwise, only a <Link to="/spell/limited_wish">limited wish</Link>, <Link to="/spell/miracle">miracle</Link>, <Link to="/spell/regenerate">regenerate</Link>, or <Link to="/spell/wish">wish</Link> spell can restore it.</p>
<p className="statblockSubHeader">Destruction</p>
<p>All of the alchemist's research notes must be collected and thrown into the vat.</p>
</>};
const _heart_explosion = {title: "Heart Explosion", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 178</Link><br/>The spirits responsible for this haunt were scared to death, and in their attempt to force mortals to understand their fear, they cause their victims' hearts to race faster and faster until they explode.</p>
<p className="statblockHeaderFull"><span>Heart Explosion</span><span>CR 13</span></p>
<p><strong>XP</strong> 25,600<br/>CE fast persistent haunt (60-ft. radius)<br/><strong>Caster Level</strong> 13th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-heart_explosion--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Heal or Perception DC 20 (for affected characters to notice pressure building around their hearts)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>58</td></tr><tr><th id="haunt-heart_explosion--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-heart_explosion--haunt-trigger">proximity</td><th id="haunt-heart_explosion--haunt-reset">Reset</th><td headers="haunt-heart_explosion--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The spectral form of a giant beating heart appears, and the hearts of everyone within the haunt's area begin to accelerate out of control. All creatures within the area are <Link to="/misc/sickened">sickened</Link>, and must succeed at a DC 21 Fortitude save each round or be <Link to="/misc/dazed">dazed</Link> and take 1d6+2 <Link to="/rule/constitution_damage">Constitution damage</Link>. If a creature who fails this saving throw has fewer than 10 hit points or reaches a Constitution score of 0, its heart forcefully explodes out of its chest, killing it instantly. The pressure of the explosion throws fragments of rib cage in all directions, dealing 2d6 points of slashing damage to all creatures within 10 feet (Reflex DC 21 negates). Creatures without hearts are immune to this haunt.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The heart explosion haunt is destroyed if a good-aligned creature spends 3 days motionlessly meditating in the center of its area.</p>
</>};
const _crushing_terror = {title: "Crushing Terror", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 179</Link><br/>Tales of a legendary linnorm have drawn many daring adventurers who wish to prove themselves by slaying the dragon. The linnorm, for its part, appreciates the sport of hunting those who seek it, and is particularly fond of crushing its victims to death with its powerful tail. The spirits of these unfortunates linger on in the form of a crushing terror haunt.</p>
<p className="statblockHeaderFull"><span>Crushing Terror</span><span>CR 14</span></p>
<p><strong>XP</strong> 38,400<br/>NE persistent haunt (30-ft. radius)<br/><strong>Caster Level</strong> 13th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-crushing_terror--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear the sound of bones snapping)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>58</td></tr><tr><th id="haunt-crushing_terror--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-crushing_terror--haunt-trigger">proximity</td><th id="haunt-crushing_terror--haunt-reset">Reset</th><td headers="haunt-crushing_terror--haunt-reset">1 hour</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Several copies of the same colossal dragon's tail snake through the haunt's area. Each round, the tails attempt to grab and constrict each creature in the area (+18 to hit, 2d6+6 points of damage plus <Link to="/umr/grab">grab</Link>, CMB +35, <Link to="/umr/constrict">constrict</Link> 2d6+18 points of damage). Each round a creature takes damage from the tail's constrict ability, one of its limbs (randomly determined) snaps into pieces, and it must succeed at a DC 22 Fortitude save or be <Link to="/misc/nauseated">nauseated</Link> for 1d4 rounds. <em>Cure</em> spells are not sufficient to repair the severely broken bones this haunt produces - only <Link to="/spell/heal">heal</Link> or stronger magic can mend them. Snapped limbs cannot be used for any purpose; having a snapped leg reduces a creature's movement speed by half when using its legs, and having more than half a creature's legs snapped prevents it from using any form of movement that uses its legs.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The crushing terror haunt is destroyed if the bodies of the linnorm's victims are retrieved from the cave where it stores them, reassembled, and buried.</p>
</>};
const _final_soldier = {title: "Final Soldier", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 179</Link><br/>The ancient antipaladin general responsible for this haunt ruled through fear, and forbade his soldiers from accepting surrender or showing mercy. His favorite way to end a battle was to order his soldiers to kill everyone but the opposing army's commander, then offer a rich reward to whichever of his soldiers could produce the opposing commander's head.</p>
<p className="statblockHeaderFull"><span>Final Soldier</span><span>CR 15</span></p>
<p><strong>XP</strong> 51,200<br/>NE belligerent chained fast persistent tenacious vaporous haunt (60-ft. radius)<br/><strong>Caster Level</strong> 15th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-final_soldier--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to hear the muted sounds of battle)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>202</td></tr><tr><th id="haunt-final_soldier--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-final_soldier--haunt-trigger">proximity</td><th id="haunt-final_soldier--haunt-reset">Reset</th><td headers="haunt-final_soldier--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A horde of armor-clad spectral soldiers rises from all sides. On the haunt's initiative count, five soldiers beset each creature in the area, and each soldier makes a single incorporeal touch attack with a spectral sword (+12 to hit, 2d6+9 points of damage/19-20). Creatures in the haunt's area can attack the soldiers, but even if they destroy an individual soldier, five soldiers continue to attack each of the creatures each round until they disperse the haunt.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The final soldier will rest only once the ancient general, who has risen as a <Link to="/template/graveknight">graveknight</Link> <Link to="/class/antipaladin">antipaladin</Link>, is permanently destroyed.</p>
</>};
const _fallen_from_the_sky = {title: "Fallen from the Sky", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 179</Link><br/>A thriving metropolis on the top of a cliff customarily executed criminals by throwing them off the precipice, until the spirits of the condemned hurled the city's head magistrate over the edge as well.</p>
<p className="statblockHeaderFull"><span>Fallen from the Sky</span><span>CR 16</span></p>
<p><strong>XP</strong> 76,800<br/>NE fast increased area persistent unyielding haunt (160-ft.-radius area aong the base and upper edge of a 200-ft.-tall cliff)<br/><strong>Caster Level</strong> 16th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-fallen_from_the_sky--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (to feel a slight tremor in the ground)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>72</td></tr><tr><th id="haunt-fallen_from_the_sky--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-fallen_from_the_sky--haunt-trigger">proximity</td><th id="haunt-fallen_from_the_sky--haunt-reset">Reset</th><td headers="haunt-fallen_from_the_sky--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The haunt causes all creatures within the haunt's area along the cliff's edge to plummet 200 feet to the ground, dealing 20d6 points of damage. The haunt temporarily negates spells, spell-like abilities, and supernatural abilities within its area as per <Link to="/spell/antimagic_field">antimagic field</Link>, except it does not block effects that deal positive energy damage. The haunt's entire area is always <Link to="/rule/difficult_terrain">difficult terrain</Link>. Extraordinary abilities, such as a monk's slow fall ability, reduce falling damage as normal. The haunt lifts creatures back to the top of the cliff on each subsequent round, but it must then succeed at a combat maneuver check to <Link to="/rule/bull_rush">bull rush</Link> each creature off the cliff (CMB +25). Creatures with natural flight can attempt a Fly check opposed by the haunt's CMB to control their descent and take no damage.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The current head magistrate of the city must go to the cliff's edge and issue individual pardons by name to everyone who was ever thrown off the cliff, even those whose names were never recorded.</p>
</>};
const _haunted_dungeon = {title: "Haunted Dungeon", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 180</Link><br/>When enough haunts gather in a single dungeon, they can combine into a gestalt haunt that infuses the entire structure with a single, malevolent will. The haunt's source typically rests in the most difficult to find or obscure location within the structure, but it moves if it senses creatures approaching it.</p>
<p className="statblockHeaderFull"><span>Haunted Dungeon</span><span>CR 17</span></p>
<p><strong>XP</strong> 102,400<br/>CE belligerent elusive free-roaming increased area persistent tenacious haunt (entire structure, up to a 170-ft. radius)<br/><strong>Caster Level</strong> 17th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-haunted_dungeon--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 10 (to notice all of the dungeon's furniture and trapings approaching)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>229</td></tr><tr><th id="haunt-haunted_dungeon--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-haunted_dungeon--haunt-trigger">proximity</td><th id="haunt-haunted_dungeon--haunt-reset">Reset</th><td headers="haunt-haunted_dungeon--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>This dungeon directs its malevolence toward everyone inside of it. Its interior is under the effects of <Link to="/spell/guards_and_wards">guards and wards</Link> at all times. If this ability is <Link to="/spell/dispel">dispelled</Link>, the haunt recreates it when it resets the following day. Once per minute, the dungeon can gather a collection of furniture and other items to form an <Link to="/monster/animated_object">animated object</Link>. It can create one Colossal animated object; alternatively, it can create two Gargantuan animated objects, four Huge animated objects, and so on. It can control up to four times as many animated objects as it can create in a minute (for a total CR of 15). For the purposes of detecting creatures, the haunted dungeon and its animated objects have <Link to="/umr/blindsight">blindsight</Link> out to a range of the entire area of the haunt, even through walls.</p>
<p className="statblockSubHeader">Destruction</p>
<p>If the entire dungeon is simultaneously placed under the effects of <Link to="/spell/hallow">hallow</Link>, the haunt is destroyed.</p>
</>};
const _flayed_suicide = {title: "Flayed Suicide", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 180</Link><br/>A flayed suicide haunt arises from the spirits of people tortured beyond insanity, until no remnants of their former essence remain. Only <Link to="/family/kyton">kytons</Link> are capable of the depths of depravity required to produce this powerful, disturbing vestige of suffering.</p>
<p className="statblockHeaderFull"><span>Flayed Suicide</span><span>CR 18</span></p>
<p><strong>XP</strong> 153,600<br/>NE belligerent persistent unyielding haunt (up to a 90-ft. radius)<br/><strong>Caster Level</strong> 20th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-flayed_suicide--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (for affected characters to notice a prickling sensation in their skin)</td></tr><tr><th id="haunt-flayed_suicide--haunt-hp">hp</th><td>243</td><th id="haunt-flayed_suicide--haunt-weak">Weaknesses</th><td colSpan={2}>-</td></tr><tr><th id="haunt-flayed_suicide--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-flayed_suicide--haunt-trigger">proximity</td><th id="haunt-flayed_suicide--haunt-reset">Reset</th><td headers="haunt-flayed_suicide--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>Hundreds of razor-sharp knives appear and carve into the skin of those in the haunt's area. An affected creature can attempt a DC 25 Fortitude save to maintain the connection between its skin and its body. On a successful save, the creature takes 10d6 points of slashing damage. Creatures that fail this saving throw take 20d6 points of slashing damage as they are flayed alive. The skin of each flayed creature animates into a necromantic puppet that single-mindedly tries to kill its source. The skin carries all of the creature's equipment (and thus the creature loses access to this equipment), has access to all of its abilities, and shares its statistics, except its hit point total is equal to half the original creature's maximum hit points. If the skin uses one of the creature's limited-use abilities, it counts against the creature's total uses for the day. A flayed creature is permanently <Link to="/misc/sickened">sickened</Link>, and is <Link to="/misc/staggered">staggered</Link> from the pain unless it succeeds at a DC 25 Fortitude save at the beginning of its turn. Even if she defeats her necrotic skin, a flayed creature's skin never regrows naturally, and can only be restored with <Link to="/spell/regenerate">regenerate</Link>.</p>
<p className="statblockSubHeader">Destruction</p>
<p>A flayed herald of a deity must be reunited with its skin and cured of its madness to give the haunt its final rest. If a character manages this feat, all flayed suicide haunts in existence on any plane are instantly destroyed.</p>
</>};
const _soul_vortex = {title: "Soul Vortex", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 180</Link><br/>The soul vortex is a gaping wound in the fabric of reality connected to the Negative Energy Plane. One may form at the site of a massive tragedy that claims hundreds of thousands of lives. The soul vortex annihilates the souls of anyone unfortunate enough to encounter it, and rips through the protections that even the most experienced adventurers consider unassailable.</p>
<p className="statblockHeaderFull"><span>Soul Vortex</span><span>CR 19</span></p>
<p><strong>XP</strong> 204,800<br/>NE belligerent fast persistent unyielding haunt (up to a 95-ft.-radius area)<br/><strong>Caster Level</strong> 20th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-soul_vortex--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 20 (for affected creatures to notice a fundamental feeling that something is wrong within them)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>256</td></tr><tr><th id="haunt-soul_vortex--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-soul_vortex--haunt-trigger">proximity</td><th id="haunt-soul_vortex--haunt-reset">Reset</th><td headers="haunt-soul_vortex--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>A black vortex appears in the center of the haunt's radius, and tugs inexorably on the souls of all creatures within its reach. Each round, before it targets their souls, the vortex first targets the magic protecting them, affecting each creature with a <Link to="/spell/greater_dispel_magic">greater dispel magic</Link> effect that targets <Link to="/spell/death_ward">death ward</Link> or any other spells that would prevent level drain first. After the dispelling effect, the creature must succeed at a DC 23 Will save to partially resist the vortex's pull. On a success, the creature takes 1d4 <Link to="/rule/negative_levels">negative levels</Link>. On a failure, that creature's soul is wrenched out of its body and destroyed. Only <Link to="/spell/miracle">miracle</Link> or <Link to="/spell/wish">wish</Link> can reconstitute a soul that the vortex devours. The vortex gains 5 <Link to="/rule/temporary_hit_points">temporary hit points</Link> for each level it drains - treat devouring a soul as draining as many negative levels as it would normally take to kill the creature. These temporary hit points stack and last for 1 hour. The soul vortex haunt is immune to the spells <Link to="/spell/heal">heal</Link> and <Link to="/spell/mass_heal">mass heal</Link>. Creatures normally immune to fear lose that immunity within this haunt's radius.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The soul vortex haunt can only be destroyed if the phylactery of a lich of CR 20 or higher that is currently destroyed and awaiting rejuvenation is cast into it. This act destroys both the vortex and the phylactery.</p>
</>};
const _twisted_wish = {title: "Twisted Wish", jsx: <><p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 181</Link><br/>A twisted wish haunt can only arise in the most extraordinary circumstances, when a genie noble of considerable power dies with vengeance in its heart. It rests in places like wells or fountains where people go to make wishes, so it can use its powers frequently.</p>
<p className="statblockHeaderFull"><span>Twisted Wish</span><span>CR 20</span></p>
<p><strong>XP</strong> 307,200<br/>LE belligerent free-roaming unyielding haunt (up to a 100-ft. radius))<br/><strong>Caster Level</strong> 20th</p>
<div className="sideNoteWrap startAlign"><ScrollContainer id="haunt-twisted_wish--table-0"><table><tbody><tr><ThLink scope="row" rowSpan={3} to="/rule/elements_of_a_haunt"><IonIcon aria-label="Haunt" icon="/icons/ghost.svg" /></ThLink><th scope="row" colSpan={2}>Notice</th><td colSpan={3}>Perception DC 35 (to notice a slight stutter in time originating from the center of its radius)</td></tr><tr><th scope="row">hp</th><td colSpan={4}>120</td></tr><tr><th id="haunt-twisted_wish--haunt-trigger" colSpan={2}>Trigger</th><td headers="haunt-twisted_wish--haunt-trigger">proximity</td><th id="haunt-twisted_wish--haunt-reset">Reset</th><td headers="haunt-twisted_wish--haunt-reset">1 day</td></tr></tbody></table></ScrollContainer></div><p className="statblockSubHeader">Effect</p>
<p>The twisted wish haunt collects the wishes of those who come near it, and stores them until it decides to grant them at its leisure and in its own warped fashion. The haunt understands all languages, as per <Link to="/spell/tongues">tongues</Link>, and does not need to manifest to hear every spoken wish and read every written wish within its radius. The haunt can manifest once per day to cast <Link to="/spell/wish">wish</Link> to grant any wish from its collection. It does not need to wait for a creature to enter its radius to manifest. The twisted wish is immune to the spells <Link to="/spell/heal">heal</Link> and <Link to="/spell/mass_heal">mass heal</Link>. Unlike the effects of a typical haunt, the wishes this haunt grants do not count as fear effects. The haunt can fly at a speed of 10 feet even when it is not manifested, but it rarely chooses to do so unless its current region isn't providing enough victims, or it perceives someone as a potential threat.</p>
<p className="statblockSubHeader">Destruction</p>
<p>The sheer number of <em>wish</em> spells this haunt can bring to bear makes it nearly invincible. Only the direct intervention of a deity can destroy the twisted wish haunt.</p>
</>};
export default {not_found:_not_found,isolation_haunt:_isolation_haunt,bloody_handprints:_bloody_handprints,scratching_behind_the_wall:_scratching_behind_the_wall,cold_spot:_cold_spot,rapping_spirit:_rapping_spirit,spectral_screams:_spectral_screams,demanding_dead:_demanding_dead,foreboding_mist:_foreboding_mist,buried_alive:_buried_alive,flytrap:_flytrap,following_footsteps:_following_footsteps,belated_arrival:_belated_arrival,bleeding_walls:_bleeding_walls,spectral_vermin:_spectral_vermin,arcane_storm:_arcane_storm,death_of_curchanus:_death_of_curchanus,unsolved_murder:_unsolved_murder,betrayal:_betrayal,droughts_end:_droughts_end,malignant_weapon:_malignant_weapon,bountiful_feast:_bountiful_feast,dimensional_tear:_dimensional_tear,robotic_reactivation:_robotic_reactivation,watery_grave:_watery_grave,devouring_maws:_devouring_maws,insidious_presence:_insidious_presence,network_of_lasers:_network_of_lasers,shifting_seasons:_shifting_seasons,enchanting_demise:_enchanting_demise,living_decay:_living_decay,whispers_from_beyond:_whispers_from_beyond,psychic_echo_anger:_psychic_echo_anger,servants_of_the_book:_servants_of_the_book,eternal_pyre:_eternal_pyre,spawn_of_the_abyss:_spawn_of_the_abyss,breach_to_the_quickening:_breach_to_the_quickening,dissolving_vat:_dissolving_vat,heart_explosion:_heart_explosion,crushing_terror:_crushing_terror,final_soldier:_final_soldier,fallen_from_the_sky:_fallen_from_the_sky,haunted_dungeon:_haunted_dungeon,flayed_suicide:_flayed_suicide,soul_vortex:_soul_vortex,twisted_wish:_twisted_wish}